modules.fpm_unpack:
// full module source
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);
    // Unpack a
    assign a_sign = a[31];
    assign a_exp  = a[30:23];
    // mantissa: implicit leading 1 for normal numbers, no implicit 1 for denormals/zero
    assign a_mant = (a[30:23] == 8'h00) ? {1'b0, a[22:0]} : {1'b1, a[22:0]};

    wire a_exp_all_ones = (a[30:23] == 8'hFF);
    wire a_exp_zero     = (a[30:23] == 8'h00);
    wire a_mant_zero    = (a[22:0] == 23'h0);

    assign a_is_nan  = a_exp_all_ones & ~a_mant_zero;
    assign a_is_inf  = a_exp_all_ones &  a_mant_zero;
    assign a_is_zero = a_exp_zero     &  a_mant_zero;

    // Unpack b
    assign b_sign = b[31];
    assign b_exp  = b[30:23];
    assign b_mant = (b[30:23] == 8'h00) ? {1'b0, b[22:0]} : {1'b1, b[22:0]};

    wire b_exp_all_ones = (b[30:23] == 8'hFF);
    wire b_exp_zero     = (b[30:23] == 8'h00);
    wire b_mant_zero    = (b[22:0] == 23'h0);

    assign b_is_nan  = b_exp_all_ones & ~b_mant_zero;
    assign b_is_inf  = b_exp_all_ones &  b_mant_zero;
    assign b_is_zero = b_exp_zero     &  b_mant_zero;

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    assign result_sign = a_sign ^ b_sign;
    assign product     = a_mant * b_mant;
    assign raw_exp     = {2'b00, a_exp} + {2'b00, b_exp} - 10'd127;
endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire overflow = product[47];

    assign norm_frac = overflow ? product[46:24] : product[45:23];
    assign norm_exp  = overflow ? raw_exp + 10'd1 : raw_exp;
    assign guard     = overflow ? product[23]     : product[22];
    assign sticky    = overflow ? |product[22:0]  : |product[21:0];

endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);
    wire round_up;
    wire [23:0] frac_rounded;
    wire [9:0]  exp_after_round;
    wire [22:0] frac_final;

    // Round to nearest, ties to even
    assign round_up = guard & (sticky | norm_frac[0]);

    // Add round bit to fraction (24-bit to catch carry)
    assign frac_rounded = {1'b0, norm_frac} + {{23{1'b0}}, round_up};

    // If rounding caused carry, increment exponent and shift fraction
    assign exp_after_round = frac_rounded[23] ? (norm_exp + 10'd1) : norm_exp;
    assign frac_final = frac_rounded[23] ? frac_rounded[23:1] : frac_rounded[22:0];

    always @(*) begin
        overflow  = 1'b0;
        underflow = 1'b0;
        result    = 32'b0;

        // norm_exp is treated as signed-extended: values >= 512 (bit[9]=1) are negative -> underflow
        // values 0 also signal underflow from upstream
        if (norm_exp == 10'd0 || norm_exp[9] == 1'b1) begin
            // Underflow: return zero
            underflow = 1'b1;
            result    = 32'b0;
        end else if (norm_exp >= 10'd255) begin
            // Overflow: return +/-Infinity
            overflow = 1'b1;
            result   = {sign, 8'hFF, 23'h0};
        end else begin
            // Check after rounding
            if (exp_after_round >= 10'd255) begin
                overflow = 1'b1;
                result   = {sign, 8'hFF, 23'h0};
            end else if (exp_after_round == 10'd0 || exp_after_round[9] == 1'b1) begin
                underflow = 1'b1;
                result    = 32'b0;
            end else begin
                result = {sign, exp_after_round[7:0], frac_final};
            end
        end
    end
endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);
    // Special case detection
    wire nan_result  = a_is_nan | b_is_nan | (a_is_inf & b_is_zero) | (a_is_zero & b_is_inf);
    wire inf_result  = (a_is_inf | b_is_inf) & ~nan_result;
    wire zero_result = (a_is_zero | b_is_zero) & ~nan_result;

    assign is_special = nan_result | inf_result | zero_result;

    always @(*) begin
        if (nan_result)
            special_result = 32'h7FC00000; // Quiet NaN
        else if (inf_result)
            special_result = {result_sign, 8'hFF, 23'h0}; // Signed Inf
        else if (zero_result)
            special_result = {result_sign, 31'h0}; // Signed zero
        else
            special_result = 32'h0;
    end
endmodule
